SELECT AVG(age) AS average_age
FROM users
WHERE smoker = 1;

SELECT COUNT(user_id) AS user_count
FROM users
WHERE interest = 'travel';

SELECT smoker, COUNT(*) AS user_count
FROM users
GROUP BY smoker;

SELECT user_id, latitude, longitude, smoker, drink_level, dress_preference, ambience
FROM users
ORDER BY age DESC;

SELECT user_id, age, activity
FROM users
ORDER BY age DESC;

SELECT AVG(u.income) AS average_income
FROM users u
WHERE u.smoker = 1 AND u.latitude BETWEEN 37 AND 39 AND u.longitude BETWEEN -123 AND -121;

SELECT AVG(income) AS average_income
FROM users
WHERE smoker = 1 AND ambience = 'party';

SELECT AVG(income) AS avg_income
FROM users
WHERE smoker = 1;

SELECT AVG(age) AS average_age
FROM users
WHERE drink_level = 'social drinker' AND budget = 'medium';

SELECT AVG(age) AS avg_age
FROM users
WHERE smoker = 1 AND dress_preference = 'formal';
